'use client';

import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

type CrmMarkdownProps = {
  source: string;
  className?: string;
  /** Use amber-tinted prose for timeline staff notes */
  variant?: 'default' | 'amber';
};

export default function CrmMarkdown({ source, className = '', variant = 'default' }: CrmMarkdownProps) {
  const tone =
    variant === 'amber'
      ? 'prose-headings:text-amber-950 prose-a:text-amber-900 prose-strong:text-amber-950'
      : '';
  return (
    <div
      className={`prose prose-sm max-w-none prose-slate prose-p:leading-relaxed prose-pre:bg-slate-900/90 prose-pre:text-slate-100 ${tone} ${className}`}
    >
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{source}</ReactMarkdown>
    </div>
  );
}
